onBarcodeSearch:
{{
  (async function() {
    await qry_search_barcode.run();
    const asset_id = qry_search_barcode.data[0]?.asset_id;
    if (!asset_id) { showAlert('Asset not found', 'warning'); return; }
    navigateTo('Asset_Page', { asset_id: asset_id });
  })()
}}

onCollectionSearch:
{{
  (async function() {
    await qry_search_collection.run();
    const collection_id = qry_search_collection.data[0]?.collection_id;
    if (!collection_id) { showAlert('Collection not found', 'warning'); return; }
    navigateTo('Collection_job_View', { collectionId: collection_id });
  })()
}}

