@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  font-size: 13px;
}

.wrap {
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.section-title {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 2px;
}

.field-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.field-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.field-input-wrap {
  display: flex;
  align-items: center;
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 0 10px;
  gap: 8px;
  height: 36px;
  transition: border-color 0.15s, box-shadow 0.15s;
}

.field-input-wrap:focus-within {
  border-color: #469BC0;
  box-shadow: 0 0 0 2px rgba(70, 155, 192, 0.1);
}

.field-icon {
  color: #469BC0;
  flex-shrink: 0;
}

.field-input {
  flex: 1;
  border: none;
  outline: none;
  font-size: 13px;
  color: #05042E;
  background: transparent;
  font-family: "Figtree", sans-serif;
}

.field-input::placeholder {
  color: #c4c2be;
}

.field-hint {
  font-size: 10px;
  color: #c4c2be;
}

.divider {
  height: 0.5px;
  background: rgba(0, 0, 0, 0.06);
}

